namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public class DocumentSummarizationService
{
    /// <summary>
    /// Produces a concise extractive summary by selecting the top-ranked sentences.
    /// Sentences are scored by word count as a simple proxy for information density.
    /// </summary>
    public string Summarize(string documentText, int maxSentences = 3)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        var sentences = SplitIntoSentences(documentText);

        if (sentences.Length <= maxSentences)
            return string.Join(" ", sentences);

        // Rank sentences by word count (longer sentences tend to carry more information)
        var ranked = sentences
            .Select((sentence, index) => (sentence, index, wordCount: sentence.Split(' ', StringSplitOptions.RemoveEmptyEntries).Length))
            .OrderByDescending(s => s.wordCount)
            .Take(maxSentences)
            .OrderBy(s => s.index) // preserve original order
            .Select(s => s.sentence);

        return string.Join(" ", ranked);
    }

    private static string[] SplitIntoSentences(string text)
    {
        return text.Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                   .Where(s => s.Length > 0)
                   .Select(s => s + ".")
                   .ToArray();
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizationService _summarizationService;

    public SummarizeController(DocumentSummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest("DocumentText is required.");

        var summary = _summarizationService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

